+// initDoltDB runs "dolt init" in a directory. Returns error if dolt isn't available.
+func initDoltDB(dir string) error {
+	cmd := exec.Command("dolt", "init", "--name", "test", "--email", "test@test.com")
+	cmd.Dir = dir
+	return cmd.Run()
+}
